() => {
  // Find the mobile menu container and its parent elements to understand the white background
  const nav = document.querySelector('#menuPrincipal nav.elementor-nav-menu--dropdown');
  const toggleBtn = document.querySelector('.elementor-menu-toggle');
  const menuContainer = document.querySelector('#menuPrincipal .elementor-nav-menu__container');

  const results = {};

  // Check the dropdown nav
  if (nav) {
    const cs = getComputedStyle(nav);
    results.dropdown = {
      bg: cs.backgroundColor,
      classes: nav.className,
      display: cs.display
    };
  } else {
    results.dropdown = 'NOT FOUND';
  }

  // Check all elements with white or near-white backgrounds in the header
  const header = document.querySelector('[data-elementor-type="header"]') || document.querySelector('.elementor-location-header');
  if (header) {
    const allEls = header.querySelectorAll('*');
    const whiteBgs = [];
    allEls.forEach(el => {
      const cs = getComputedStyle(el);
      if (cs.display !== 'none' && (cs.backgroundColor === 'rgb(255, 255, 255)' || cs.backgroundColor === 'rgba(255, 255, 255, 1)' || cs.backgroundColor === '#ffffff' || cs.backgroundColor === '#fff')) {
        whiteBgs.push({
          tag: el.tagName,
          id: el.id,
          classes: el.className.substring(0, 120),
          bg: cs.backgroundColor
        });
      }
    });
    results.whiteBgElements = whiteBgs.slice(0, 15);
  }

  // Check the navigation container that's visible
  const visibleNav = document.querySelector('.elementor-nav-menu__container');
  if (visibleNav) {
    const cs = getComputedStyle(visibleNav);
    results.navContainer = {
      bg: cs.backgroundColor,
      display: cs.display,
      classes: visibleNav.className,
      parent: visibleNav.parentElement?.className?.substring(0, 100)
    };
  }

  // Also look for the toggle panel content
  const toggleContent = document.querySelector('.elementor-menu-toggle__container') || document.querySelector('.elementor-nav-menu--toggle');
  if (toggleContent) {
    const cs = getComputedStyle(toggleContent);
    results.toggleContent = {
      bg: cs.backgroundColor,
      classes: toggleContent.className
    };
  }

  return JSON.stringify(results, null, 2);
}

