() => {
  const nav = document.querySelector('nav.elementor-nav-menu--dropdown.elementor-nav-menu__container');
  if (!nav) return 'NOT FOUND';

  // Walk up the DOM tree to find the widget container
  let el = nav;
  const parents = [];
  while (el && parents.length < 10) {
    parents.push({
      tag: el.tagName,
      id: el.id || '',
      classes: (el.className || '').toString().substring(0, 150),
      bg: getComputedStyle(el).backgroundColor
    });
    el = el.parentElement;
  }

  // Also check the widget wrapper ID
  const widget = nav.closest('.elementor-widget-nav-menu');
  const widgetId = widget ? widget.getAttribute('data-id') : 'none';
  const widgetSection = widget ? widget.closest('.elementor-section, .elementor-element[data-id]') : null;
  const sectionId = widgetSection ? widgetSection.getAttribute('data-id') : 'none';

  return JSON.stringify({
    parents,
    widgetDataId: widgetId,
    sectionDataId: sectionId,
    navHtml: nav.outerHTML.substring(0, 300)
  }, null, 2);
}

