() => {
  const nav = document.querySelector('nav.elementor-nav-menu--dropdown.elementor-nav-menu__container');
  if (!nav) return 'NOT FOUND';

  // Check inline styles
  const inlineStyle = nav.getAttribute('style');

  // Check all matching CSS rules
  const sheets = document.styleSheets;
  const matches = [];

  for (let i = 0; i < sheets.length; i++) {
    try {
      const rules = sheets[i].cssRules;
      for (let j = 0; j < rules.length; j++) {
        const rule = rules[j];
        if (rule.selectorText && rule.style && rule.style.backgroundColor) {
          try {
            if (nav.matches(rule.selectorText)) {
              matches.push({
                selector: rule.selectorText,
                bg: rule.style.backgroundColor,
                priority: rule.style.getPropertyPriority('background-color'),
                sheet: sheets[i].href || 'inline'
              });
            }
          } catch(e) {}
        }
      }
    } catch(e) {}
  }

  return JSON.stringify({
    inlineStyle,
    matchingRules: matches
  }, null, 2);
}

