input.function:
() => {
  const toggle = document.querySelector('.elementor-menu-toggle');
  if (toggle) toggle.click();

  return new Promise(resolve => {
    setTimeout(() => {
      const dropdown = document.querySelector('nav.elementor-nav-menu--dropdown');
      if (!dropdown) { resolve('no dropdown'); return; }

      // Expand Cultura submenu (4th item)
      const items = dropdown.querySelectorAll('li.menu-item-has-children');
      items.forEach(item => {
        const subMenu = item.querySelector('ul.sub-menu');
        if (subMenu) {
          subMenu.style.display = 'block';
          subMenu.style.visibility = 'visible';
          subMenu.style.opacity = '1';
          item.classList.add('elementor-active');
        }
      });

      resolve(`Expanded ${items.length} submenus`);
    }, 500);
  });
}

